        .expireAfterWrite(1, TimeUnit.HOURS).build();

    public void loginFailed(String key) {
        int attempts = attemptsCache.getIfPresent(key) != null ? attemptsCache.getIfPresent(key) : 0;
        attemptsCache.put(key, attempts + 1);
