const bcrypt = require('bcrypt');
const SALT_ROUNDS = 12;

// Validate complexity
function validatePassword(password) {
  const regex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*]).{12,}$/;
  if (!regex.test(password)) throw new Error('Password does not meet complexity requirements');
